// ----------- Sparklines for rolling MAPE -----------
function genSparkline(seed, n, base = 2.1, amp = 0.4) {
  const rand = mulberry32(seed);
  const out = [];
  let v;
  for (let i = 0; i < n; i++) {
    v = base + (rand() - 0.5) * amp + Math.sin(i / (n / 4)) * 0.15;
    out.push(+v.toFixed(3));
  }
  return out;
}

export const SPARKLINE_24H = genSparkline(11, 24, 2.08, 0.35);
export const SPARKLINE_7D = genSparkline(22, 7, 2.14, 0.25);
export const SPARKLINE_30D = genSparkline(33, 30, 2.31, 0.5);

// ----------- Error distribution histogram -----------
function genErrorDistribution() {
  const buckets = [];
  for (let x = -5; x <= 5; x += 0.5) {
    const mu = 0.5, sigma = 1.8;
    const y = Math.exp(-((x - mu) ** 2) / (2 * sigma * sigma));
    const count = Math.round(y * 130 + (mulberry32(Math.floor((x + 5) * 10))() - 0.5) * 8);
    buckets.push({ bucket: x.toFixed(1), x, count: Math.max(0, count) });
  }
  return buckets;
}

export const ERROR_DISTRIBUTION = genErrorDistribution();
